// Generated from Claude Design handoff. Do not hand-edit page markup here; update from New UI Build when design changes.
export const handoffPages = {
  "findCreators": {
    "html": "<main style=\"position:relative;z-index:10; padding-top:5.5rem;\">\n\n<!-- ===== HEADER STRIP ===== -->\n<section class=\"px-6 lg:px-16 pt-10 pb-8\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"flex items-center gap-2 text-[11px] text-[var(--text-dim)] mb-4 reveal-up\">\n      <a href=\"/\" class=\"hover:text-[var(--text)] transition-colors\">Home</a>\n      <span class=\"opacity-40\">/</span>\n      <span class=\"text-[var(--text)]\">Find Creators</span>\n    </div>\n    <div class=\"grid lg:grid-cols-12 gap-6 items-end reveal-up\">\n      <div class=\"lg:col-span-7\">\n        <div class=\"eyebrow mb-2\">Browse the network · US-only</div>\n        <h1 class=\"text-4xl md:text-5xl serif font-medium leading-[1.05]\">\n          Verified creators, <span class=\"gold-text\">sorted by what matters</span>.\n        </h1>\n        <p class=\"text-sm text-[var(--text-secondary)] max-w-md mt-3\">\n          Filter by primary pillar — Video Production, Photography, or Post Production — then narrow by specialty. Every creator commits to one pillar and 1&ndash;3 specialties.\n        </p>\n      </div>\n      <div class=\"lg:col-span-5\">\n        <div class=\"liquid-glass rounded-xl p-1.5 flex items-center gap-2\">\n          <svg class=\"w-4 h-4 text-[var(--text-dim)] ml-2\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z\"></path></svg>\n          <input id=\"search-input\" type=\"text\" placeholder=\"Search by name, studio, specialty, city\" class=\"flex-1 bg-transparent border-0 text-sm py-2 focus:outline-none placeholder:text-[var(--text-dim)]\" style=\"color:var(--text);\">\n          <button class=\"btn-gold text-[11px]\" style=\"padding:0.5rem 1rem;\">Search</button>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ===== RESULTS LAYOUT ===== -->\n<section class=\"px-6 lg:px-16 pb-24\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"grid lg:grid-cols-12 gap-8\">\n\n      <!-- FILTER SIDEBAR -->\n      <aside class=\"lg:col-span-3 reveal-up\">\n        <div class=\"liquid-glass rounded-2xl p-5 lg:sticky lg:top-24\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <div class=\"eyebrow\">Filters</div>\n            <button id=\"reset-btn\" class=\"text-[10px] text-[var(--text-dim)] hover:text-[var(--gold)] transition-colors tracking-wider uppercase\">Reset</button>\n          </div>\n\n          <div class=\"mb-5\">\n            <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-2\">Primary pillar</div>\n            <div class=\"flex flex-col gap-1\" id=\"pillar-rail\"></div>\n          </div>\n\n          <div class=\"divider mb-5\"></div>\n\n          <div class=\"mb-5\">\n            <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-2\">Tier</div>\n            <div class=\"flex flex-col gap-1\" data-filter-group=\"tier\">\n              <button class=\"filter-chip active\" data-value=\"all\"><span>Any tier</span></button>\n              <button class=\"filter-chip\" data-value=\"Elite\"><span>Elite</span></button>\n              <button class=\"filter-chip\" data-value=\"Proven\"><span>Proven</span></button>\n              <button class=\"filter-chip\" data-value=\"Verified\"><span>Verified</span></button>\n            </div>\n          </div>\n\n          <div class=\"divider mb-5\"></div>\n\n          <div class=\"mb-5\">\n            <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-2\">Budget · USD</div>\n            <div class=\"flex flex-col gap-1\" data-filter-group=\"budget\">\n              <button class=\"filter-chip active\" data-value=\"all\"><span>Any budget</span></button>\n              <button class=\"filter-chip\" data-value=\"low\"><span>Under $750</span></button>\n              <button class=\"filter-chip\" data-value=\"mid\"><span>$750 – $2,000</span></button>\n              <button class=\"filter-chip\" data-value=\"high\"><span>$2,000+</span></button>\n            </div>\n          </div>\n\n          <div class=\"divider mb-5\"></div>\n\n          <div>\n            <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-2\">Availability</div>\n            <div class=\"flex flex-col gap-1\" data-filter-group=\"avail\">\n              <button class=\"filter-chip active\" data-value=\"all\"><span>Any availability</span></button>\n              <button class=\"filter-chip\" data-value=\"open\"><span>Open now</span></button>\n              <button class=\"filter-chip\" data-value=\"2wk\"><span>Within 2 weeks</span></button>\n              <button class=\"filter-chip\" data-value=\"4wk\"><span>Within 4 weeks</span></button>\n            </div>\n          </div>\n        </div>\n      </aside>\n\n      <!-- RESULTS -->\n      <div class=\"lg:col-span-9\">\n        <div class=\"flex items-center justify-between mb-5 reveal-up\">\n          <div class=\"text-xs text-[var(--text-secondary)]\">\n            Showing <span id=\"result-count\" class=\"text-[var(--text)] font-medium\">12</span> of <span class=\"text-[var(--text)] font-medium\">12</span> verified creators\n          </div>\n          <div class=\"liquid-glass rounded-lg flex items-center gap-2 px-3 py-1.5\">\n            <span class=\"text-[10px] uppercase tracking-wider text-[var(--text-dim)]\">Sort</span>\n            <select id=\"sort-select\" class=\"bg-transparent text-xs focus:outline-none\" style=\"color:var(--text);\">\n              <option value=\"featured\">Featured</option>\n              <option value=\"rating\">Highest rated</option>\n              <option value=\"price-asc\">Price · low to high</option>\n              <option value=\"price-desc\">Price · high to low</option>\n              <option value=\"newest\">Newest</option>\n            </select>\n          </div>\n        </div>\n\n        <div id=\"results-grid\" class=\"grid md:grid-cols-2 xl:grid-cols-3 gap-4\">\n          <!-- cards rendered by JS -->\n        </div>\n\n        <div id=\"empty-state\" class=\"liquid-glass rounded-2xl p-12 text-center\" style=\"display:none;\">\n          <div class=\"text-3xl serif mb-2\">No matches yet</div>\n          <p class=\"text-sm text-[var(--text-secondary)] max-w-sm mx-auto mb-4\">Loosen the filters or pick a different pillar. New creators verify into the network every week.</p>\n          <button id=\"empty-reset\" class=\"btn-ghost text-xs\">Clear all filters</button>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n</main>",
    "script": "\n\n\n// ===== CREATORS =====\n// Each creator has ONE primary pillar and 1–3 specialties inside it.\n// Old standalone categories (Drone, Podcast, Brand Content, Events, Editing/Post)\n// are now specialties under the three pillars.\nconst CREATORS = [\n  { id: 1, studio: \"Aria Visual Studio\", name: \"Aria Vasquez\",\n    pillar: \"photo\", specialties: [\"Brand & Commercial Photography\", \"Editorial & Press\", \"Headshots & Portraits\"],\n    city: \"Miami, FL\", tier: \"Elite\", price: 850, budget: \"mid\", rating: 4.9, reviews: 64, avail: \"open\", years: 7,\n    blurb: \"Editorial commercial photography with a bold, narrative eye.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1494790108377-be9c29b29330.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1542038784456-1ea8e935640e.png\",\n    featured: true },\n  { id: 2, studio: \"SoundWave Audio Co.\", name: \"Jordan Mitchell\",\n    pillar: \"post\", specialties: [\"Podcast Audio Editing\", \"Sound Design & Mixing\"],\n    city: \"New York, NY\", tier: \"Proven\", price: 350, budget: \"low\", rating: 4.8, reviews: 53, avail: \"open\", years: 7,\n    blurb: \"200+ podcasts edited & mixed. Tight noise floor, fast Monday turnarounds.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1507003211169-0a1dd7228f2d.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1590602847861-f357a9332bbc.png\",\n    featured: true },\n  { id: 3, studio: \"LensCraft Studios\", name: \"David Park\",\n    pillar: \"video\", specialties: [\"Brand Films & Commercials\", \"Music Videos\", \"Corporate & Internal Video\"],\n    city: \"Los Angeles, CA\", tier: \"Elite\", price: 2500, budget: \"high\", rating: 5.0, reviews: 31, avail: \"2wk\", years: 5,\n    blurb: \"Cinematic brand films. RED-certified cinematography with a small crew.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1438761681033-6461ffad8d80.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1485846234645-a62644f84728.png\",\n    featured: true },\n  { id: 4, studio: \"Skyframe Aerial\", name: \"Mateo Reyes\",\n    pillar: \"video\", specialties: [\"Drone & Aerial Video\", \"Real Estate Video\"],\n    city: \"Austin, TX\", tier: \"Verified\", price: 650, budget: \"low\", rating: 4.7, reviews: 22, avail: \"open\", years: 4,\n    blurb: \"Part 107 certified. Aerial cinematography for real estate, hospitality, brand.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1500648767791-00dcc994a43e.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1506947411487-a56738267384.png\",\n    featured: false },\n  { id: 5, studio: \"Bondi Studio\", name: \"Maya Chen\",\n    pillar: \"video\", specialties: [\"Short-Form & Social (Reels/TikTok/UGC)\", \"Brand Films & Commercials\"],\n    city: \"Chicago, IL\", tier: \"Verified\", price: 1200, budget: \"mid\", rating: 4.8, reviews: 48, avail: \"2wk\", years: 6,\n    blurb: \"Monthly social-first video for boutique brands. Reels, UGC, short-form ads.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1573497019940-1c28c88b4f3e.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1516035069371-29a1b244cc32.png\",\n    featured: false },\n  { id: 6, studio: \"Northgrade Color\", name: \"Aaron Wei\",\n    pillar: \"post\", specialties: [\"Color Grading\", \"Video Editing (Long-Form)\"],\n    city: \"Seattle, WA\", tier: \"Elite\", price: 400, budget: \"low\", rating: 4.9, reviews: 41, avail: \"4wk\", years: 8,\n    blurb: \"DaVinci-certified colorist. Editorial commercials and music videos.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1463453091185-61582044d556.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1574717024653-61fd2cf4d44d.png\",\n    featured: false },\n  { id: 7, studio: \"Greene Street Films\", name: \"Naomi Greene\",\n    pillar: \"video\", specialties: [\"Brand Films & Commercials\", \"Documentary & Interviews\", \"Event & Conference Video\"],\n    city: \"Brooklyn, NY\", tier: \"Elite\", price: 3500, budget: \"high\", rating: 4.9, reviews: 28, avail: \"4wk\", years: 9,\n    blurb: \"Narrative-driven brand films. Past clients: Equinox, Aesop, Tribeca Film Fest.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1531746020798-e6953c6e8e04.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1492691527719-9d1e07e534b4.png\",\n    featured: true },\n  { id: 8, studio: \"Studio Mojave\", name: \"Iris Patel\",\n    pillar: \"photo\", specialties: [\"Food & Hospitality\", \"Real Estate Photography\", \"Lifestyle & Fashion\"],\n    city: \"Phoenix, AZ\", tier: \"Proven\", price: 750, budget: \"mid\", rating: 4.6, reviews: 19, avail: \"open\", years: 5,\n    blurb: \"Hospitality + interiors photography. Hotels, restaurants, resorts.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1544005313-94ddf0286df2.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1502672260266-1c1ef2d93688.png\",\n    featured: false },\n  { id: 9, studio: \"Cumulus Events Co\", name: \"Dre Williams\",\n    pillar: \"video\", specialties: [\"Event & Conference Video\", \"Short-Form & Social (Reels/TikTok/UGC)\"],\n    city: \"Atlanta, GA\", tier: \"Verified\", price: 900, budget: \"mid\", rating: 4.8, reviews: 36, avail: \"2wk\", years: 6,\n    blurb: \"Conference and corporate event coverage. Same-day social cutdowns.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1607746882042-944635dfe10e.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1540575467063-178a50c2df87.png\",\n    featured: false },\n  { id: 10, studio: \"Pellizzari Editorial\", name: \"Sofia Pellizzari\",\n    pillar: \"photo\", specialties: [\"Editorial & Press\", \"Lifestyle & Fashion\", \"Headshots & Portraits\"],\n    city: \"Boston, MA\", tier: \"Elite\", price: 1100, budget: \"mid\", rating: 4.9, reviews: 52, avail: \"open\", years: 8,\n    blurb: \"Editorial fashion + portrait. Featured in Harper's, Vogue Italia.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1487412720507-e7ab37603c6f.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1496217590455-aa63a8350eea.png\",\n    featured: false },\n  { id: 11, studio: \"Crosscut Edit Room\", name: \"Marcus Bell\",\n    pillar: \"post\", specialties: [\"Motion Graphics & VFX\", \"Short-Form Editing\", \"Video Editing (Long-Form)\"],\n    city: \"Portland, OR\", tier: \"Proven\", price: 550, budget: \"low\", rating: 4.7, reviews: 33, avail: \"open\", years: 6,\n    blurb: \"Motion + edit suite. After Effects, kinetic typography, brand-channel cutdowns.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1633332755192-727a05c4013d.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1633419461186-7d40a38105ec.png\",\n    featured: false },\n  { id: 12, studio: \"Sterling Product Studio\", name: \"Reese Sterling\",\n    pillar: \"photo\", specialties: [\"Product & Still Life\", \"Brand & Commercial Photography\"],\n    city: \"Denver, CO\", tier: \"Proven\", price: 950, budget: \"mid\", rating: 4.8, reviews: 27, avail: \"open\", years: 6,\n    blurb: \"Tabletop + product photography for DTC brands. Clean white + lifestyle composition.\",\n    avatar: \"/images/creatorbridge/handoff/photo-1502823403499-6ccfcf4fb453.png\",\n    cover: \"/images/creatorbridge/handoff/photo-1556228720-195a672e8a03.png\",\n    featured: false }\n];\n\nconst state = {\n  pillar: 'all',         // 'all' | 'video' | 'photo' | 'post'\n  specialties: new Set(),// active specialty filter (only meaningful when pillar is set)\n  tier: 'all', budget: 'all', avail: 'all', sort: 'featured', q: ''\n};\n\nconst $ = (s) => root.querySelector(s);\nconst $$ = (s) => Array.from(root.querySelectorAll(s));\n\n// ===== PILLAR RAIL =====\nfunction renderPillarRail() {\n  const rail = $('#pillar-rail');\n  const items = [\n    { key: 'all', label: 'All services', short: 'ALL', sub: CREATORS.length + ' creators' }\n  ].concat(window.CB.PILLARS.map(p => ({\n    key: p.key, label: p.label, short: p.short.toUpperCase(),\n    sub: CREATORS.filter(c => c.pillar === p.key).length + ' creators'\n  })));\n\n  rail.innerHTML = items.map(it => {\n    const isActive = state.pillar === it.key;\n    const pillar = it.key === 'all' ? null : window.CB.pillarByKey(it.key);\n    const specHtml = (isActive && pillar) ? `\n      <div class=\"specialty-list\" data-for=\"${it.key}\">\n        ${pillar.specialties.map(s => `\n          <button class=\"specialty-chip${state.specialties.has(s) ? ' active' : ''}\" data-spec=\"${s}\">\n            <span class=\"box\"></span>\n            <span>${s}</span>\n          </button>\n        `).join('')}\n        ${state.specialties.size > 0 ? `<button class=\"text-[10px] text-[var(--text-dim)] hover:text-[var(--gold)] transition-colors mt-1.5 ml-1 tracking-wider uppercase text-left\" id=\"clear-spec\">Clear specialties</button>` : ''}\n      </div>` : '';\n\n    return `\n      <div>\n        <button class=\"filter-chip pillar-chip${isActive ? ' active' : ''}\" data-pillar=\"${it.key}\">\n          <span><span class=\"pkey\">${it.short}</span>${it.label}</span>\n          <span class=\"count\">${it.sub.split(' ')[0]}</span>\n        </button>\n        ${specHtml}\n      </div>`;\n  }).join('');\n\n  // bindings\n  $$('[data-pillar]').forEach(btn => {\n    btn.addEventListener('click', () => {\n      const k = btn.dataset.pillar;\n      if (state.pillar !== k) state.specialties.clear();\n      state.pillar = k;\n      renderPillarRail();\n      applyFilters();\n    });\n  });\n  $$('[data-spec]').forEach(btn => {\n    btn.addEventListener('click', () => {\n      const s = btn.dataset.spec;\n      if (state.specialties.has(s)) state.specialties.delete(s);\n      else state.specialties.add(s);\n      renderPillarRail();\n      applyFilters();\n    });\n  });\n  const clr = $('#clear-spec');\n  if (clr) clr.addEventListener('click', () => {\n    state.specialties.clear();\n    renderPillarRail();\n    applyFilters();\n  });\n}\n\n// ===== STAR =====\nfunction starSvg(filled) {\n  return `<svg width=\"11\" height=\"11\" viewBox=\"0 0 20 20\" fill=\"${filled ? 'currentColor' : 'none'}\" stroke=\"currentColor\" stroke-width=\"1.2\"><path d=\"M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z\"/></svg>`;\n}\n\n// ===== CARD =====\nfunction cardHtml(c) {\n  const stars = [1,2,3,4,5].map(i => starSvg(i <= Math.round(c.rating))).join('');\n  const pillar = window.CB.pillarByKey(c.pillar);\n  const specChips = c.specialties.slice(0, 3).map(s =>\n    `<span class=\"specialty-pill\">${s}</span>`).join('');\n  return `\n    <a href=\"/creator/demo\" class=\"creator-card\">\n      <div class=\"cover\">\n        <img src=\"${c.cover}\" alt=\"${c.studio}\">\n        <div class=\"pillar-label\"><span class=\"dot\"></span>${pillar.label}</div>\n        <div class=\"tier-chips\">\n          <span class=\"tag-gold\">${c.tier}</span>\n          ${c.avail === 'open' ? '<span class=\"tag-green\">Available</span>' : ''}\n        </div>\n        <div class=\"avatar\"><img src=\"${c.avatar}\" alt=\"${c.name}\"></div>\n      </div>\n      <div class=\"body\">\n        <div class=\"flex items-start justify-between gap-2 mb-1\">\n          <div class=\"font-semibold text-sm leading-tight\">${c.studio}</div>\n          <div class=\"flex items-center gap-1 text-[var(--gold)] shrink-0\">\n            ${stars}\n            <span class=\"font-semibold text-xs text-[var(--text)] ml-1\">${c.rating.toFixed(1)}</span>\n          </div>\n        </div>\n        <div class=\"text-[11px] text-[var(--text-dim)] mb-3\">${c.name} · ${c.city} · ${c.years}+ yrs</div>\n        <p class=\"text-xs text-[var(--text-secondary)] leading-relaxed mb-4 flex-1\">${c.blurb}</p>\n        <div class=\"flex flex-wrap gap-1.5 mb-4\">\n          ${specChips}\n        </div>\n        <div class=\"flex items-center justify-between pt-3 border-t border-[var(--border)]\">\n          <div>\n            <div class=\"text-[10px] uppercase tracking-wider text-[var(--text-dim)]\">from · USD</div>\n            <div class=\"text-base serif gold-text leading-none\">$${c.price.toLocaleString()}</div>\n          </div>\n          <span class=\"btn-ghost text-[10px]\" style=\"padding:0.4rem 0.85rem;\">View profile</span>\n        </div>\n      </div>\n    </a>`;\n}\n\nfunction applyFilters() {\n  let filtered = CREATORS.filter(c => {\n    if (state.pillar !== 'all' && c.pillar !== state.pillar) return false;\n    if (state.specialties.size > 0) {\n      const hit = c.specialties.some(s => state.specialties.has(s));\n      if (!hit) return false;\n    }\n    if (state.tier !== 'all' && c.tier !== state.tier) return false;\n    if (state.budget !== 'all' && c.budget !== state.budget) return false;\n    if (state.avail !== 'all') {\n      const order = { open: 0, '2wk': 1, '4wk': 2 };\n      if (order[c.avail] > order[state.avail]) return false;\n    }\n    if (state.q) {\n      const q = state.q.toLowerCase();\n      const hay = (c.studio + ' ' + c.name + ' ' + c.city + ' ' + c.specialties.join(' ') + ' ' + c.blurb).toLowerCase();\n      if (!hay.includes(q)) return false;\n    }\n    return true;\n  });\n\n  if (state.sort === 'rating') filtered.sort((a,b) => b.rating - a.rating);\n  else if (state.sort === 'price-asc') filtered.sort((a,b) => a.price - b.price);\n  else if (state.sort === 'price-desc') filtered.sort((a,b) => b.price - a.price);\n  else if (state.sort === 'newest') filtered.sort((a,b) => a.years - b.years);\n  else filtered.sort((a,b) => (b.featured?1:0) - (a.featured?1:0));\n\n  const grid = $('#results-grid');\n  const empty = $('#empty-state');\n  if (filtered.length === 0) {\n    grid.innerHTML = '';\n    empty.style.display = 'block';\n  } else {\n    grid.innerHTML = filtered.map(cardHtml).join('');\n    empty.style.display = 'none';\n  }\n  $('#result-count').textContent = filtered.length;\n}\n\n// Other filter chip handlers\n$$('[data-filter-group]').forEach(group => {\n  const key = group.dataset.filterGroup;\n  group.querySelectorAll('.filter-chip').forEach(chip => {\n    chip.addEventListener('click', () => {\n      group.querySelectorAll('.filter-chip').forEach(c => c.classList.remove('active'));\n      chip.classList.add('active');\n      state[key] = chip.dataset.value;\n      applyFilters();\n    });\n  });\n});\n\n$('#sort-select').addEventListener('change', (e) => { state.sort = e.target.value; applyFilters(); });\n$('#search-input').addEventListener('input', (e) => { state.q = e.target.value; applyFilters(); });\n\nfunction reset() {\n  state.pillar = 'all'; state.specialties.clear();\n  state.tier = 'all'; state.budget = 'all'; state.avail = 'all'; state.q = ''; state.sort = 'featured';\n  $('#search-input').value = '';\n  $('#sort-select').value = 'featured';\n  $$('[data-filter-group]').forEach(g => {\n    g.querySelectorAll('.filter-chip').forEach(c => c.classList.toggle('active', c.dataset.value === 'all'));\n  });\n  renderPillarRail();\n  applyFilters();\n}\n$('#reset-btn').addEventListener('click', reset);\n$('#empty-reset').addEventListener('click', reset);\n\n// Handle ?pillar=… or legacy ?lane=… from landing page links\nconst params = new URLSearchParams(location.search);\nconst urlPillar = params.get('pillar') || params.get('lane');\nif (urlPillar) {\n  const legacyMap = { video: 'video', photo: 'photo', post: 'post',\n                       podcast: 'post', drone: 'video', events: 'video', brand: 'video' };\n  const target = legacyMap[urlPillar];\n  if (target) state.pillar = target;\n}\n\nrenderPillarRail();\napplyFilters();\n"
  },
  "projectBoard": {
    "html": "<main style=\"position:relative;z-index:10; padding-top:5.5rem;\">\n\n<!-- ===== HEADER STRIP ===== -->\n<section class=\"px-6 lg:px-16 pt-10 pb-6\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"flex items-center gap-2 text-[11px] text-[var(--text-dim)] mb-4 reveal-up\">\n      <a href=\"/\" class=\"hover:text-[var(--text)] transition-colors\">Home</a>\n      <span class=\"opacity-40\">/</span>\n      <span class=\"text-[var(--text)]\">Project Board</span>\n    </div>\n    <div class=\"grid lg:grid-cols-12 gap-6 items-end mb-6 reveal-up\">\n      <div class=\"lg:col-span-7\">\n        <div class=\"eyebrow mb-2\">Open production briefs · US only</div>\n        <h1 class=\"text-4xl md:text-5xl serif font-medium leading-[1.05]\">\n          Curated work. <span class=\"gold-text\">Scoped before money moves.</span>\n        </h1>\n        <p class=\"text-sm text-[var(--text-secondary)] max-w-md mt-4\">\n          Every brief is reviewed by the CreatorBridge team and tagged by pillar + specialty. Creators apply with proof; clients shortlist before any USD retainer is held.\n        </p>\n      </div>\n      <div class=\"lg:col-span-5 flex lg:justify-end gap-2\">\n        <button id=\"post-brief-btn\" class=\"btn-gold\">\n          <svg class=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M12 4v16m8-8H4\"></path></svg>\n          Post a brief\n        </button>\n        <a href=\"/find\" class=\"btn-ghost\">Browse creators</a>\n      </div>\n    </div>\n\n    <!-- FILTERS -->\n    <div class=\"flex flex-wrap items-center gap-2 reveal-up\">\n      <div class=\"text-[10px] uppercase tracking-[0.2em] text-[var(--text-dim)] mr-2\">Pillar</div>\n      <button class=\"filter-pill active\" data-pillar=\"all\"><span class=\"pk\">ALL</span> All briefs <span id=\"count-all\" style=\"opacity:0.6\"></span></button>\n      <button class=\"filter-pill\" data-pillar=\"video\"><span class=\"pk\">01</span> Video Production <span class=\"opacity-60\" id=\"count-video\"></span></button>\n      <button class=\"filter-pill\" data-pillar=\"photo\"><span class=\"pk\">02</span> Photography <span class=\"opacity-60\" id=\"count-photo\"></span></button>\n      <button class=\"filter-pill\" data-pillar=\"post\"><span class=\"pk\">03</span> Post Production <span class=\"opacity-60\" id=\"count-post\"></span></button>\n      <div class=\"ml-auto flex items-center gap-2\">\n        <select id=\"sort\" class=\"bg-transparent border border-[var(--border)] rounded-lg px-3 py-1.5 text-xs\" style=\"color:var(--text);\">\n          <option value=\"newest\">Newest</option>\n          <option value=\"budget-desc\">Budget · high to low</option>\n          <option value=\"budget-asc\">Budget · low to high</option>\n          <option value=\"applied\">Most applied</option>\n        </select>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ===== RESULTS ===== -->\n<section class=\"px-6 lg:px-16 pb-24\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"grid lg:grid-cols-12 gap-6\">\n\n      <!-- LIST -->\n      <div class=\"lg:col-span-5 space-y-3\" id=\"brief-list\"></div>\n\n      <!-- DETAIL -->\n      <div class=\"lg:col-span-7\">\n        <div id=\"detail-pane\" class=\"detail-pane\"></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n</main>\n\n<!-- ===== POST BRIEF MODAL ===== -->\n<div class=\"modal-backdrop\" id=\"post-modal\">\n  <div class=\"modal-box p-6 lg:p-8\">\n    <div class=\"flex items-center justify-between mb-5\">\n      <div>\n        <div class=\"eyebrow mb-1\">Post a production brief · US only</div>\n        <h3 class=\"text-xl serif\">Tell us what you're producing</h3>\n      </div>\n      <button id=\"close-modal\" class=\"w-9 h-9 rounded-full border border-[var(--border)] flex items-center justify-center hover:border-[var(--gold)] hover:text-[var(--gold)] transition-colors\">\n        <svg class=\"w-4 h-4\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M6 18L18 6M6 6l12 12\"></path></svg>\n      </button>\n    </div>\n\n    <div class=\"space-y-4\">\n      <label class=\"block\">\n        <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Project title</div>\n        <input type=\"text\" class=\"input\" placeholder=\"e.g. Product photography for spring launch\">\n      </label>\n      <div class=\"grid grid-cols-2 gap-3\">\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Primary pillar</div>\n          <select id=\"modal-pillar\" class=\"input\">\n            <option value=\"video\">Video Production</option>\n            <option value=\"photo\" selected>Photography</option>\n            <option value=\"post\">Post Production</option>\n          </select>\n        </label>\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Specialty</div>\n          <select id=\"modal-specialty\" class=\"input\"></select>\n        </label>\n      </div>\n      <div class=\"grid grid-cols-2 gap-3\">\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">US location</div>\n          <input type=\"text\" class=\"input\" placeholder=\"City, ST · or Remote\">\n        </label>\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Deadline</div>\n          <input type=\"text\" class=\"input\" placeholder=\"e.g. Jun 15 or Ongoing\">\n        </label>\n      </div>\n      <div class=\"grid grid-cols-2 gap-3\">\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Budget min · USD</div>\n          <input type=\"number\" class=\"input\" placeholder=\"$\">\n        </label>\n        <label class=\"block\">\n          <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Budget max · USD</div>\n          <input type=\"number\" class=\"input\" placeholder=\"$\">\n        </label>\n      </div>\n      <label class=\"block\">\n        <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Brief</div>\n        <textarea class=\"input-area\" rows=\"5\" placeholder=\"Deliverables, mood, references, timeline…\"></textarea>\n      </label>\n      <div class=\"liquid-glass rounded-xl p-4 text-xs text-[var(--text-secondary)]\">\n        Briefs are reviewed within 24 hrs. Once live, verified US creators can apply with proof — you choose who to shortlist before any USD retainer is held.\n      </div>\n      <div class=\"flex gap-2 justify-end pt-2\">\n        <button id=\"cancel-modal\" class=\"btn-ghost text-xs\">Cancel</button>\n        <button class=\"btn-gold text-xs\">Submit for review</button>\n      </div>\n    </div>\n  </div>\n</div>",
    "script": "\n\n\n// ===== BRIEFS =====\n// Every brief tagged with primary pillar + specialty (within that pillar).\nconst BRIEFS = [\n  {\n    id: 1, title: \"Product Photography for E-Commerce Launch\", client: \"BeautyBrand Co\",\n    pillar: \"photo\", specialty: \"Product & Still Life\",\n    location: \"New York, NY\", budgetMin: 800, budgetMax: 1500,\n    posted: \"2 days ago\", deadline: \"May 30\", applied: 3, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1556228720-195a672e8a03.png\",\n    summary: \"Launching a new skincare line — need a US-based product photographer to shoot 30+ items on clean white backgrounds plus 12 lifestyle composition frames.\",\n    deliverables: [\"30 product images · white background\", \"12 lifestyle composition shots\", \"Retouched + color-corrected\", \"Web + print-ready files\", \"Usage rights · 18 months\"],\n    tags: [\"product photography\", \"Adobe Lightroom\", \"white background\", \"skincare\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1571781926291-c477ebfd024b.png\", \"/images/creatorbridge/handoff/photo-1607082348824-0a96f2a4b9da.png\"]\n  },\n  {\n    id: 2, title: \"YouTube Channel Intro Animation (30 sec)\", client: \"TechReviewPro\",\n    pillar: \"post\", specialty: \"Motion Graphics & VFX\",\n    location: \"Remote · US\", budgetMin: 300, budgetMax: 600,\n    posted: \"5 days ago\", deadline: \"Jun 12\", applied: 7, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1633419461186-7d40a38105ec.png\",\n    summary: \"Need a motion designer for a punchy 30-second intro animation for a tech review channel. Bold typography, kinetic energy, tech-forward.\",\n    deliverables: [\"30-second intro animation\", \"5-second outro variant\", \"1080p + 4K masters\", \"Editable AE project file\", \"2 revision rounds\"],\n    tags: [\"After Effects\", \"motion graphics\", \"logo animation\", \"kinetic type\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1633419461186-7d40a38105ec.png\"]\n  },\n  {\n    id: 3, title: \"Monthly Social Video Package — Real Estate\", client: \"LuxRealty Group\",\n    pillar: \"video\", specialty: \"Short-Form & Social (Reels/TikTok/UGC)\",\n    location: \"Los Angeles, CA\", budgetMin: 1200, budgetMax: 2500,\n    posted: \"1 week ago\", deadline: \"Ongoing\", applied: 12, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1502672260266-1c1ef2d93688.png\",\n    summary: \"Boutique real estate agency needs a monthly social-first video package: 4 Reels, 8 Stories, captions and strategy. Looking for a long-term partner in LA.\",\n    deliverables: [\"4 Reels with motion edits · monthly\", \"8 Stories · monthly\", \"Caption copy + strategy\", \"Monthly content calendar\"],\n    tags: [\"Instagram\", \"Reels\", \"real estate\", \"monthly retainer\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1600585154340-be6161a56a0c.png\"]\n  },\n  {\n    id: 4, title: \"Weekly Podcast Audio Editing — Long-Term\", client: \"The Business Pod\",\n    pillar: \"post\", specialty: \"Podcast Audio Editing\",\n    location: \"Remote · US\", budgetMin: 150, budgetMax: 300,\n    posted: \"3 days ago\", deadline: \"Recurring\", applied: 5, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1590602847861-f357a9332bbc.png\",\n    summary: \"Established weekly business podcast (200+ episodes) seeking a reliable audio editor. ~45 min raw audio per week. Long-term preferred.\",\n    deliverables: [\"Weekly episode edit · 45 min\", \"Noise cleanup + leveling\", \"Show notes + chapter markers\", \"Same-day Monday turnaround\"],\n    tags: [\"Adobe Audition\", \"podcast editing\", \"Descript\", \"long-term\"],\n    refs: []\n  },\n  {\n    id: 5, title: \"Aerial Video for Luxury Property Listings\", client: \"Sunset Realty Miami\",\n    pillar: \"video\", specialty: \"Drone & Aerial Video\",\n    location: \"Miami, FL\", budgetMin: 400, budgetMax: 800,\n    posted: \"1 day ago\", deadline: \"Jun 5\", applied: 2, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1506947411487-a56738267384.png\",\n    summary: \"Need a Part 107 licensed drone operator for aerial footage of 4 waterfront properties. 4K footage + edited 30-second listing reels.\",\n    deliverables: [\"4K aerial footage · 4 properties\", \"Color graded clips\", \"Edited 30-second listing reels\", \"Aerial stills · 8 per property\"],\n    tags: [\"Part 107\", \"DJI Mavic\", \"real estate\", \"4K\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1567496898669-ee935f5f647a.png\"]\n  },\n  {\n    id: 6, title: \"Conference Recap Video · Annual Summit\", client: \"Verge Conference\",\n    pillar: \"video\", specialty: \"Event & Conference Video\",\n    location: \"San Francisco, CA\", budgetMin: 3000, budgetMax: 5000,\n    posted: \"6 days ago\", deadline: \"Jul 1\", applied: 9, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1540575467063-178a50c2df87.png\",\n    summary: \"Two-day tech conference (~2000 attendees) needs a recap video team: keynote captures, hallway b-roll, attendee interviews, 3-minute hype edit.\",\n    deliverables: [\"Multi-cam keynote captures\", \"Hallway b-roll + atmosphere\", \"8 attendee interviews\", \"3-min hype recap edit\", \"Social cutdowns · 6 variants\"],\n    tags: [\"multi-cam\", \"live event\", \"interviews\", \"social\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1505373877841-8d25f7d46678.png\"]\n  },\n  {\n    id: 7, title: \"Restaurant Menu Photography\", client: \"Saigon Sky\",\n    pillar: \"photo\", specialty: \"Food & Hospitality\",\n    location: \"Chicago, IL\", budgetMin: 600, budgetMax: 1200,\n    posted: \"4 days ago\", deadline: \"Jun 20\", applied: 4, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1517248135467-4c7edcad34c4.png\",\n    summary: \"Modern Vietnamese restaurant launching new spring menu — need 24 hero dishes shot. Natural light preferred, moody-but-clean aesthetic.\",\n    deliverables: [\"24 hero dish images\", \"8 atmosphere shots · interior\", \"Print menu + Instagram crops\", \"Retouched + color matched\"],\n    tags: [\"food photography\", \"natural light\", \"restaurant\", \"editorial\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1565299624946-b28f40a0ae38.png\"]\n  },\n  {\n    id: 8, title: \"Documentary Short for Nonprofit\", client: \"Hope Foundation\",\n    pillar: \"video\", specialty: \"Documentary & Interviews\",\n    location: \"Multi-city · NYC, Detroit, ATL\", budgetMin: 4000, budgetMax: 8000,\n    posted: \"2 weeks ago\", deadline: \"Aug 15\", applied: 11, status: \"Shortlisting\",\n    cover: \"/images/creatorbridge/handoff/photo-1485846234645-a62644f84728.png\",\n    summary: \"12-minute documentary short profiling 3 program beneficiaries across NYC, Detroit, and Atlanta. Interviews + verite + supporting footage.\",\n    deliverables: [\"3-city travel + production\", \"12-min documentary edit\", \"3 interview-only versions for digital\", \"Sound design + original score\", \"Festival-ready masters\"],\n    tags: [\"documentary\", \"interviews\", \"verite\", \"travel\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1492691527719-9d1e07e534b4.png\"]\n  },\n  {\n    id: 9, title: \"Editorial Headshots — Founder Series\", client: \"Stride Magazine\",\n    pillar: \"photo\", specialty: \"Editorial & Press\",\n    location: \"Brooklyn, NY\", budgetMin: 1500, budgetMax: 2500,\n    posted: \"5 days ago\", deadline: \"Jun 28\", applied: 6, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1554384645-13eab165c24b.png\",\n    summary: \"Magazine feature on 8 founders — editorial portraits, studio + on-location. Need a photographer with strong editorial sensibility.\",\n    deliverables: [\"8 founder portraits · 2hrs each\", \"Editorial finishing\", \"Print + digital deliverables\", \"Usage · 18 months print/digital\"],\n    tags: [\"editorial\", \"portrait\", \"magazine\", \"founders\"],\n    refs: [\"/images/creatorbridge/handoff/photo-1531123897727-8f129e1688ce.png\"]\n  },\n  {\n    id: 10, title: \"Brand Color Pass · Spring Campaign\", client: \"Northgrade · Aesop\",\n    pillar: \"post\", specialty: \"Color Grading\",\n    location: \"Remote · US\", budgetMin: 800, budgetMax: 1600,\n    posted: \"1 day ago\", deadline: \"Jun 8\", applied: 4, status: \"Open\",\n    cover: \"/images/creatorbridge/handoff/photo-1574717024653-61fd2cf4d44d.png\",\n    summary: \"Color grading pass on a 90-second spring campaign film — moody warm palette, two-pass workflow with editorial team.\",\n    deliverables: [\"90-sec primary grade\", \"Two revision passes\", \"Social-format reformats\", \"Editorial collab\"],\n    tags: [\"DaVinci Resolve\", \"editorial\", \"warm grade\", \"campaign\"],\n    refs: []\n  }\n];\n\nconst state = { pillar: 'all', sort: 'newest', activeId: 1 };\nconst $ = (s) => root.querySelector(s);\nconst $$ = (s) => Array.from(root.querySelectorAll(s));\n\nfunction fmt(n) { return '$' + n.toLocaleString(); }\n\nfunction pillarLabelHtml(b) {\n  const p = window.CB.pillarByKey(b.pillar);\n  return `<span class=\"pillar-lane-label\"><span class=\"pillar\">${p.label}</span><span class=\"sep\">·</span><span class=\"spec\">${b.specialty}</span></span>`;\n}\n\nfunction pillarIconSvg(key) {\n  if (key === 'video') return `<svg width=\"18\" height=\"18\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z\"/></svg>`;\n  if (key === 'photo') return `<svg width=\"18\" height=\"18\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z\"/><circle cx=\"12\" cy=\"13\" r=\"3.5\"/></svg>`;\n  return `<svg width=\"18\" height=\"18\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z\"/></svg>`;\n}\n\nfunction listCardHtml(b) {\n  const active = state.activeId === b.id ? ' active' : '';\n  return `\n    <div class=\"brief-card${active}\" data-id=\"${b.id}\">\n      <div class=\"flex items-start gap-3 mb-2.5\">\n        <div class=\"lane-icon\">${pillarIconSvg(b.pillar)}</div>\n        <div class=\"flex-1 min-w-0\">\n          <div class=\"flex items-center gap-2 mb-1 flex-wrap\">\n            <span class=\"tag-green\">${b.status}</span>\n            <span class=\"text-[10px] text-[var(--text-dim)]\">${b.posted}</span>\n          </div>\n          <div class=\"font-medium text-sm leading-tight mb-1.5\">${b.title}</div>\n          ${pillarLabelHtml(b)}\n        </div>\n      </div>\n      <div class=\"text-[11px] text-[var(--text-dim)] mb-3\">${b.client} · ${b.location}</div>\n      <div class=\"flex items-center justify-between text-[11px]\">\n        <div class=\"text-[var(--gold)] font-semibold serif\">${fmt(b.budgetMin)} – ${fmt(b.budgetMax)} <span class=\"text-[9px] text-[var(--text-dim)] tracking-wider ml-0.5\">USD</span></div>\n        <div class=\"text-[var(--text-dim)]\">${b.applied} applied</div>\n      </div>\n    </div>`;\n}\n\nfunction detailHtml(b) {\n  const refsHtml = b.refs.length\n    ? `<div class=\"grid grid-cols-${Math.min(b.refs.length, 3)} gap-2 mb-6\">\n        ${b.refs.map(r => `<div class=\"parallax-wrap rounded-lg overflow-hidden aspect-video\"><img src=\"${r}\" class=\"parallax-img w-full h-full object-cover scale-105\"></div>`).join('')}\n      </div>` : '';\n  return `\n    <div class=\"liquid-glass rounded-2xl overflow-hidden\">\n      <div class=\"aspect-[16/8] relative overflow-hidden\">\n        <img src=\"${b.cover}\" class=\"w-full h-full object-cover\" alt=\"${b.title}\">\n        <div class=\"absolute inset-0\" style=\"background:linear-gradient(to top, rgba(13,13,15,0.95), rgba(13,13,15,0.4));\"></div>\n        <div class=\"absolute bottom-0 left-0 right-0 p-6\">\n          <div class=\"flex items-center gap-2 mb-2 flex-wrap\">\n            ${pillarLabelHtml(b)}\n            <span class=\"tag-green\">${b.status}</span>\n            <span class=\"text-[10px] text-[var(--text-dim)] ml-auto\">${b.posted}</span>\n          </div>\n          <h2 class=\"text-2xl md:text-3xl serif font-medium leading-tight mb-1\">${b.title}</h2>\n          <div class=\"text-xs text-[var(--text-dim)]\">${b.client} · ${b.location} · Deadline ${b.deadline}</div>\n        </div>\n      </div>\n\n      <div class=\"p-6 md:p-8\">\n        <div class=\"grid grid-cols-3 gap-4 mb-6 liquid-glass rounded-xl p-4\">\n          <div>\n            <div class=\"text-[9px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1\">Budget · USD</div>\n            <div class=\"text-base serif gold-text leading-none\">${fmt(b.budgetMin)}–${fmt(b.budgetMax)}</div>\n          </div>\n          <div>\n            <div class=\"text-[9px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1\">Applied</div>\n            <div class=\"text-base serif leading-none\">${b.applied} creators</div>\n          </div>\n          <div>\n            <div class=\"text-[9px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1\">Deadline</div>\n            <div class=\"text-base serif leading-none\">${b.deadline}</div>\n          </div>\n        </div>\n\n        <div class=\"eyebrow mb-2\">The brief</div>\n        <p class=\"text-sm text-[var(--text-secondary)] leading-relaxed mb-6\">${b.summary}</p>\n\n        <div class=\"eyebrow mb-3\">Deliverables</div>\n        <ul class=\"space-y-2 mb-6\">\n          ${b.deliverables.map(d => `<li class=\"flex items-start gap-2 text-xs text-[var(--text)]/85\">\n            <svg class=\"w-3 h-3 text-[var(--gold)] mt-1 shrink-0\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 13l4 4L19 7\"/></svg>\n            ${d}\n          </li>`).join('')}\n        </ul>\n\n        ${refsHtml ? `<div class=\"eyebrow mb-3\">Reference</div>${refsHtml}` : ''}\n\n        <div class=\"eyebrow mb-3\">Tags</div>\n        <div class=\"flex flex-wrap gap-1.5 mb-8\">\n          ${b.tags.map(t => `<span class=\"tag-plain\">${t}</span>`).join('')}\n        </div>\n\n        <div class=\"liquid-glass rounded-xl p-5 mb-6\">\n          <div class=\"eyebrow mb-2\">Booking structure · USD</div>\n          <div class=\"flex items-center justify-between text-xs mb-2\"><span class=\"text-[var(--text-secondary)]\">Held in escrow on award</span><span class=\"text-[var(--gold)] serif\">50%</span></div>\n          <div class=\"flex items-center justify-between text-xs mb-2\"><span class=\"text-[var(--text-secondary)]\">Released on delivery approval</span><span class=\"text-[var(--gold)] serif\">50%</span></div>\n          <div class=\"flex items-center justify-between text-xs\"><span class=\"text-[var(--text-secondary)]\">Client booking fee</span><span class=\"text-[var(--text-dim)]\">5%</span></div>\n        </div>\n\n        <div class=\"flex flex-col sm:flex-row gap-2\">\n          <button class=\"btn-gold flex-1 justify-center\">Apply with proof</button>\n          <button class=\"btn-ghost\">Save for later</button>\n          <button class=\"btn-ghost\">Share</button>\n        </div>\n        <p class=\"text-[10px] text-[var(--text-dim)] mt-3 text-center\">Applications include your relevant work + a short pitch. Client shortlists from verified US creators only.</p>\n      </div>\n    </div>`;\n}\n\nfunction render() {\n  let list = BRIEFS.filter(b => state.pillar === 'all' || b.pillar === state.pillar);\n  if (state.sort === 'budget-desc') list.sort((a,b) => b.budgetMax - a.budgetMax);\n  else if (state.sort === 'budget-asc') list.sort((a,b) => a.budgetMin - b.budgetMin);\n  else if (state.sort === 'applied') list.sort((a,b) => b.applied - a.applied);\n  $('#brief-list').innerHTML = list.length ? list.map(listCardHtml).join('') :\n    `<div class=\"liquid-glass rounded-2xl p-8 text-center\"><div class=\"text-lg serif mb-1\">No open briefs in this pillar</div><div class=\"text-xs text-[var(--text-dim)]\">Switch pillars or check back soon.</div></div>`;\n\n  // bind click\n  $$('.brief-card').forEach(card => {\n    card.addEventListener('click', () => {\n      state.activeId = parseInt(card.dataset.id);\n      render();\n    });\n  });\n\n  // detail — prefer the active brief if visible, else first in list\n  const active = list.find(b => b.id === state.activeId) || list[0];\n  $('#detail-pane').innerHTML = active ? detailHtml(active) : '<div class=\"text-xs text-[var(--text-dim)] p-8\">No brief selected.</div>';\n}\n\nfunction updateCounts() {\n  $('#count-all').textContent = `(${BRIEFS.length})`;\n  ['video', 'photo', 'post'].forEach(k => {\n    $('#count-' + k).textContent = `(${BRIEFS.filter(b => b.pillar === k).length})`;\n  });\n}\n\n// Filter handlers\n$$('[data-pillar]').forEach(btn => {\n  btn.addEventListener('click', () => {\n    $$('[data-pillar]').forEach(b => b.classList.remove('active'));\n    btn.classList.add('active');\n    state.pillar = btn.dataset.pillar;\n    render();\n  });\n});\n$('#sort').addEventListener('change', e => { state.sort = e.target.value; render(); });\n\n// Modal pillar/specialty cascade\nfunction refreshSpecOptions() {\n  const sel = $('#modal-pillar').value;\n  const p = window.CB.pillarByKey(sel);\n  $('#modal-specialty').innerHTML = p.specialties.map(s => `<option>${s}</option>`).join('');\n}\n$('#modal-pillar').addEventListener('change', refreshSpecOptions);\nrefreshSpecOptions();\n\n// Modal\nconst modal = $('#post-modal');\n$('#post-brief-btn').addEventListener('click', () => modal.classList.add('open'));\n$('#close-modal').addEventListener('click', () => modal.classList.remove('open'));\n$('#cancel-modal').addEventListener('click', () => modal.classList.remove('open'));\nmodal.addEventListener('click', (e) => { if (e.target === modal) modal.classList.remove('open'); });\n\nupdateCounts();\nrender();\n"
  },
  "rateCalculator": {
    "html": "<main style=\"position:relative;z-index:10; padding-top:5.5rem;\">\n\n<!-- ===== HEADER ===== -->\n<section class=\"px-6 lg:px-16 pt-10 pb-8\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"flex items-center gap-2 text-[11px] text-[var(--text-dim)] mb-4 reveal-up\">\n      <a href=\"/\" class=\"hover:text-[var(--text)] transition-colors\">Home</a>\n      <span class=\"opacity-40\">/</span>\n      <span class=\"text-[var(--text)]\">Rate Calculator</span>\n    </div>\n    <div class=\"grid lg:grid-cols-12 gap-6 items-end reveal-up\">\n      <div class=\"lg:col-span-7\">\n        <div class=\"eyebrow mb-2\">Creator pricing tool · US markets</div>\n        <h1 class=\"text-4xl md:text-5xl serif font-medium leading-[1.05]\">\n          Build rates with <span class=\"gold-text\">professional confidence</span>.\n        </h1>\n        <p class=\"text-sm text-[var(--text-secondary)] max-w-lg mt-4\">\n          Calibrate scope, US market, and experience into a USD quote that holds up — and see which package lane the work belongs in. Pick your primary pillar first, then your specialty.\n        </p>\n      </div>\n      <div class=\"lg:col-span-5 flex lg:justify-end\">\n        <div class=\"liquid-glass rounded-xl px-4 py-3 flex items-center gap-3\">\n          <svg class=\"w-4 h-4 text-[var(--gold)]\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z\"/></svg>\n          <div class=\"text-[11px] text-[var(--text-secondary)] max-w-xs leading-snug\">For pricing strategy — not the public booking flow. Always negotiate scope first.</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ===== CALCULATOR ===== -->\n<section class=\"px-6 lg:px-16 pb-24\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"grid lg:grid-cols-12 gap-6\">\n\n      <!-- LEFT: INPUTS -->\n      <div class=\"lg:col-span-8 space-y-5\">\n\n        <!-- PILLAR PICKER -->\n        <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <div>\n              <div class=\"eyebrow mb-1\">Primary pillar</div>\n              <div class=\"text-sm text-[var(--text-secondary)]\">Choose one. Sets your base hourly rate and the specialties available below.</div>\n            </div>\n          </div>\n          <div class=\"grid md:grid-cols-3 gap-3\" id=\"pillars\"></div>\n        </div>\n\n        <!-- SPECIALTY PICKER -->\n        <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <div>\n              <div class=\"eyebrow mb-1\">Specialty</div>\n              <div class=\"text-sm text-[var(--text-secondary)]\" id=\"spec-helper\">Pick the type of work this quote covers. Affects market multiplier and deliverable unit.</div>\n            </div>\n            <div class=\"text-right\">\n              <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)]\">Adjusted base</div>\n              <div class=\"text-base serif gold-text leading-none\" id=\"adj-base\">$150/hr</div>\n            </div>\n          </div>\n          <div class=\"flex flex-wrap gap-2\" id=\"spec-list\"></div>\n        </div>\n\n        <!-- MARKET + EXPERIENCE -->\n        <div class=\"grid md:grid-cols-2 gap-5\">\n          <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n            <div class=\"eyebrow mb-3\">US market</div>\n            <select id=\"market\" class=\"input mb-3\">\n              <option value=\"0.92\">Smaller US metro · 0.92×</option>\n              <option value=\"1.0\">Other US market · 1.0×</option>\n              <option value=\"1.1\">Mid-tier · Austin, Miami, Chicago, Atlanta · 1.1×</option>\n              <option value=\"1.25\">Major · Boston, Seattle, DC, Denver · 1.25×</option>\n              <option value=\"1.4\" selected>Top-tier · NYC, LA, SF · 1.4×</option>\n            </select>\n            <div class=\"text-[11px] text-[var(--text-dim)] leading-relaxed\">Adjusts the base USD rate for local cost-of-doing-business. Calibrated from CreatorBridge booking data — US only.</div>\n          </div>\n          <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n            <div class=\"eyebrow mb-3\">Experience</div>\n            <div class=\"flex gap-1.5\">\n              <button class=\"seg-btn\" data-exp=\"0.7\">2–3 yrs</button>\n              <button class=\"seg-btn active\" data-exp=\"1.0\">4–6 yrs</button>\n              <button class=\"seg-btn\" data-exp=\"1.4\">7+ yrs</button>\n            </div>\n            <div class=\"text-[11px] text-[var(--text-dim)] leading-relaxed mt-3\">More experience earns a higher rate — and lets you charge for direction, not just hours.</div>\n          </div>\n        </div>\n\n        <!-- SCOPE BUILDER -->\n        <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n          <div class=\"eyebrow mb-4\">Scope of work</div>\n          <div class=\"grid md:grid-cols-2 gap-x-8 gap-y-5\">\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\" id=\"duration-label\">Shoot duration</div>\n                <div class=\"text-xs text-[var(--gold)] serif\" id=\"duration-out\">Full-day · 8 hr</div>\n              </div>\n              <div class=\"flex gap-1.5\">\n                <button class=\"seg-btn\" data-dur=\"4\">Half · 4hr</button>\n                <button class=\"seg-btn active\" data-dur=\"8\">Full · 8hr</button>\n                <button class=\"seg-btn\" data-dur=\"16\">2-day</button>\n                <button class=\"seg-btn\" data-dur=\"24\">3-day</button>\n              </div>\n            </div>\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\">Locations</div>\n                <div class=\"text-xs text-[var(--gold)] serif\" id=\"loc-out\">1 location</div>\n              </div>\n              <input id=\"loc-slider\" type=\"range\" min=\"1\" max=\"5\" value=\"1\" class=\"tweak-slider\">\n            </div>\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\" id=\"deliver-label\">Edited images</div>\n                <div class=\"text-xs text-[var(--gold)] serif\" id=\"deliver-out\">40</div>\n              </div>\n              <input id=\"deliver-slider\" type=\"range\" min=\"5\" max=\"200\" value=\"40\" class=\"tweak-slider\">\n            </div>\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\">Crew size</div>\n                <div class=\"text-xs text-[var(--gold)] serif\" id=\"crew-out\">1 (just you)</div>\n              </div>\n              <input id=\"crew-slider\" type=\"range\" min=\"1\" max=\"6\" value=\"1\" class=\"tweak-slider\">\n            </div>\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\">Revision rounds</div>\n                <div class=\"text-xs text-[var(--gold)] serif\" id=\"rev-out\">2 included</div>\n              </div>\n              <input id=\"rev-slider\" type=\"range\" min=\"1\" max=\"8\" value=\"2\" class=\"tweak-slider\">\n            </div>\n\n            <div>\n              <div class=\"flex items-center justify-between mb-2\">\n                <div class=\"text-sm font-medium\">Usage rights</div>\n              </div>\n              <select id=\"usage\" class=\"input\">\n                <option value=\"1.0\">Personal / portfolio · 1.0×</option>\n                <option value=\"1.25\" selected>Commercial · 1 year · 1.25×</option>\n                <option value=\"1.6\">Commercial · 3 years · 1.6×</option>\n                <option value=\"2.0\">Buyout · all media · 2.0×</option>\n              </select>\n            </div>\n\n            <div class=\"md:col-span-2 flex flex-wrap gap-4 pt-2 border-t border-[var(--border)]\">\n              <label class=\"flex items-center gap-2 text-xs text-[var(--text-secondary)] cursor-pointer\">\n                <input type=\"checkbox\" id=\"travel\" class=\"accent-[var(--gold)]\" style=\"width:14px;height:14px;\">\n                Out-of-market travel ($550 flat day rate)\n              </label>\n              <label class=\"flex items-center gap-2 text-xs text-[var(--text-secondary)] cursor-pointer\">\n                <input type=\"checkbox\" id=\"raw\" class=\"accent-[var(--gold)]\" style=\"width:14px;height:14px;\">\n                Include RAW files / project files (+10%)\n              </label>\n              <label class=\"flex items-center gap-2 text-xs text-[var(--text-secondary)] cursor-pointer\">\n                <input type=\"checkbox\" id=\"rush\" class=\"accent-[var(--gold)]\" style=\"width:14px;height:14px;\">\n                Rush delivery · &lt;72 hr (+15%)\n              </label>\n            </div>\n          </div>\n        </div>\n\n        <!-- COSTS -->\n        <div class=\"liquid-glass rounded-2xl p-6 reveal-up\">\n          <div class=\"flex items-center justify-between mb-4\">\n            <div>\n              <div class=\"eyebrow mb-1\">Production costs · optional</div>\n              <div class=\"text-xs text-[var(--text-secondary)]\">Track what comes off the top so margin stays visible. USD.</div>\n            </div>\n            <div class=\"text-right\">\n              <div class=\"text-[10px] text-[var(--text-dim)] uppercase tracking-wider\">Total costs</div>\n              <div class=\"text-lg serif gold-text leading-none\" id=\"cost-total\">$0</div>\n            </div>\n          </div>\n          <div class=\"grid grid-cols-2 md:grid-cols-4 gap-3\" id=\"cost-rows\">\n            <div>\n              <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Gear rental</div>\n              <input type=\"number\" min=\"0\" data-cost class=\"input\" placeholder=\"$0\" value=\"0\">\n            </div>\n            <div>\n              <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Studio / venue</div>\n              <input type=\"number\" min=\"0\" data-cost class=\"input\" placeholder=\"$0\" value=\"0\">\n            </div>\n            <div>\n              <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Crew (additional)</div>\n              <input type=\"number\" min=\"0\" data-cost class=\"input\" placeholder=\"$0\" value=\"0\">\n            </div>\n            <div>\n              <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1.5\">Travel + per diem</div>\n              <input type=\"number\" min=\"0\" data-cost class=\"input\" placeholder=\"$0\" value=\"0\">\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <!-- RIGHT: LIVE QUOTE -->\n      <div class=\"lg:col-span-4\">\n        <div class=\"liquid-glass rounded-2xl p-6 reveal-up\" style=\"position:sticky; top:6rem;\">\n          <div class=\"eyebrow mb-1\">Recommended quote</div>\n          <div class=\"flex items-baseline gap-2 mb-1\">\n            <span class=\"text-5xl serif gold-text leading-none\" id=\"quote-out\">$2,450</span>\n            <span class=\"text-xs text-[var(--text-dim)] mb-1\">USD</span>\n          </div>\n          <div class=\"text-[11px] text-[var(--text-dim)] mb-5\" id=\"quote-sub\">Full-day · NYC · 4–6 yrs</div>\n\n          <div class=\"space-y-2 text-xs mb-5\">\n            <div class=\"flex justify-between\"><span class=\"text-[var(--text-dim)]\">Base creative fee</span><span id=\"base-out\" class=\"serif text-[var(--text)]\">$0</span></div>\n            <div class=\"flex justify-between\"><span class=\"text-[var(--text-dim)]\">Deliverables</span><span id=\"del-out\" class=\"serif text-[var(--text)]\">$0</span></div>\n            <div class=\"flex justify-between\"><span class=\"text-[var(--text-dim)]\">Usage rights</span><span id=\"usage-out\" class=\"serif text-[var(--text)]\">×1.0</span></div>\n            <div class=\"flex justify-between\"><span class=\"text-[var(--text-dim)]\">Add-ons</span><span id=\"addon-out\" class=\"serif text-[var(--text)]\">$0</span></div>\n            <div class=\"flex justify-between\"><span class=\"text-[var(--text-dim)]\">Production costs</span><span id=\"cost-out\" class=\"serif text-[var(--text)]\">$0</span></div>\n          </div>\n          <div class=\"divider mb-4\"></div>\n          <div class=\"grid grid-cols-2 gap-3 mb-5 text-center\">\n            <div>\n              <div class=\"text-[9px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1\">Net to you</div>\n              <div class=\"text-lg serif text-[var(--gold)]\" id=\"net-out\">$0</div>\n            </div>\n            <div>\n              <div class=\"text-[9px] tracking-[0.2em] uppercase text-[var(--text-dim)] mb-1\">Effective margin</div>\n              <div class=\"text-lg serif\" id=\"margin-out\">—</div>\n            </div>\n          </div>\n\n          <div class=\"space-y-2\">\n            <button class=\"btn-gold w-full justify-center text-xs\">Save as quote draft</button>\n            <button class=\"btn-ghost w-full justify-center text-xs\">Build into a package</button>\n          </div>\n\n          <div class=\"mt-5 p-3 rounded-lg\" style=\"background:rgba(201,168,76,0.04); border:1px solid rgba(201,168,76,0.12);\">\n            <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--gold)] mb-1\">50/50 escrow split · USD</div>\n            <div class=\"flex justify-between text-[11px]\"><span class=\"text-[var(--text-dim)]\">Held on booking</span><span class=\"serif text-[var(--gold)]\" id=\"retainer-out\">$0</span></div>\n            <div class=\"flex justify-between text-[11px]\"><span class=\"text-[var(--text-dim)]\">Released on delivery</span><span class=\"serif text-[var(--gold)]\" id=\"release-out\">$0</span></div>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- PACKAGE SUGGESTION -->\n    <div class=\"mt-10 reveal-up\">\n      <div class=\"flex items-end justify-between mb-4\">\n        <div>\n          <div class=\"eyebrow mb-2\">Package fit</div>\n          <h2 class=\"text-2xl md:text-3xl serif font-medium leading-tight\">Where this quote lands.</h2>\n        </div>\n        <div class=\"text-xs text-[var(--text-dim)] hidden md:block\">Use these as ladder positioning when listing your services.</div>\n      </div>\n      <div class=\"grid md:grid-cols-3 gap-4\" id=\"pkg-grid\"></div>\n    </div>\n  </div>\n</section>\n\n</main>",
    "script": "\n\n\n// ===== PILLAR BASES =====\n// Each pillar sets a base hourly rate. Then specialty applies a small multiplier.\n// The deliverable unit (what slider 3 measures) is also per pillar.\nconst PILLAR_BASE = {\n  video: { hourly: 220, unit: 220, unitLabel: \"Finished minutes\", unitMin: 1,  unitMax: 30,  unitDefault: 3,  durationLabel: \"Shoot duration\" },\n  photo: { hourly: 150, unit: 35,  unitLabel: \"Edited images\",   unitMin: 5,  unitMax: 200, unitDefault: 40, durationLabel: \"Shoot duration\" },\n  post:  { hourly: 95,  unit: 0,   unitLabel: \"Edit hours\",       unitMin: 4,  unitMax: 80,  unitDefault: 16, durationLabel: \"Production duration\" }\n};\n\n// Per-specialty multiplier on the base hourly. 1.0 = pillar default.\n// Some specialties command a premium (commercial, brand films, color grading).\n// Some come in lower (real estate, headshots, podcast audio).\nconst SPECIALTY_MULT = {\n  // Video Production\n  \"Brand Films & Commercials\":         1.20,\n  \"Wedding Films\":                     1.05,\n  \"Event & Conference Video\":          1.00,\n  \"Music Videos\":                      1.10,\n  \"Documentary & Interviews\":          1.10,\n  \"Video Podcasts\":                    0.90,\n  \"Short-Form & Social (Reels/TikTok/UGC)\": 0.95,\n  \"Real Estate Video\":                 0.85,\n  \"Drone & Aerial Video\":              1.05,\n  \"Corporate & Internal Video\":        1.00,\n  // Photography\n  \"Brand & Commercial Photography\":    1.15,\n  \"Wedding Photography\":               1.05,\n  \"Event Photography\":                 0.95,\n  \"Headshots & Portraits\":             0.85,\n  \"Product & Still Life\":              1.00,\n  \"Real Estate Photography\":           0.85,\n  \"Lifestyle & Fashion\":               1.10,\n  \"Editorial & Press\":                 1.10,\n  \"Drone & Aerial Photography\":        1.05,\n  \"Food & Hospitality\":                1.00,\n  // Post Production\n  \"Video Editing (Long-Form)\":         1.05,\n  \"Short-Form Editing\":                0.90,\n  \"Color Grading\":                     1.15,\n  \"Motion Graphics & VFX\":             1.15,\n  \"Sound Design & Mixing\":             1.05,\n  \"Podcast Audio Editing\":             0.85,\n  \"Photo Retouching\":                  0.90,\n  \"Documentary Editing\":               1.10\n};\n\nconst state = {\n  pillar: 'photo', specialty: 'Brand & Commercial Photography',\n  market: 1.4, exp: 1.0,\n  duration: 8, locations: 1, deliver: 40,\n  crew: 1, revisions: 2, usage: 1.25,\n  travel: false, raw: false, rush: false,\n  costs: [0, 0, 0, 0]\n};\n\nconst $ = (s) => root.querySelector(s);\nconst $$ = (s) => Array.from(root.querySelectorAll(s));\nconst fmt = (n) => '$' + Math.round(n).toLocaleString();\n\n// ===== RENDER PILLARS =====\nfunction renderPillars() {\n  const pillars = window.CB.PILLARS;\n  const order = ['video', 'photo', 'post'];\n  $('#pillars').innerHTML = order.map((key, i) => {\n    const p = pillars.find(x => x.key === key);\n    const base = PILLAR_BASE[key];\n    return `\n      <button class=\"pillar-pick${state.pillar === key ? ' active' : ''}\" data-pillar=\"${key}\">\n        <div class=\"pcheck\"></div>\n        <div class=\"pnum\">Pillar 0${i + 1}</div>\n        <div class=\"plabel\">${p.label}</div>\n        <div class=\"pbase\">${fmt(base.hourly)}/hr base · USD</div>\n      </button>`;\n  }).join('');\n  $$('[data-pillar]').forEach(b => b.addEventListener('click', () => {\n    if (state.pillar === b.dataset.pillar) return;\n    state.pillar = b.dataset.pillar;\n    const pillar = window.CB.pillarByKey(state.pillar);\n    // pick first specialty by default\n    state.specialty = pillar.specialties[0];\n    // reset deliverable unit defaults for this pillar\n    const base = PILLAR_BASE[state.pillar];\n    state.deliver = base.unitDefault;\n    const slider = $('#deliver-slider');\n    slider.min = base.unitMin; slider.max = base.unitMax; slider.value = base.unitDefault;\n    $('#deliver-label').textContent = base.unitLabel;\n    $('#duration-label').textContent = base.durationLabel;\n    renderPillars();\n    renderSpecialties();\n    compute();\n  }));\n}\n\n// ===== RENDER SPECIALTIES =====\nfunction renderSpecialties() {\n  const pillar = window.CB.pillarByKey(state.pillar);\n  const list = $('#spec-list');\n  list.innerHTML = pillar.specialties.map(s => {\n    const m = SPECIALTY_MULT[s] || 1.0;\n    const tag = m === 1 ? '' : ` <span class=\"mult\">${m >= 1 ? '+' : ''}${Math.round((m - 1) * 100)}%</span>`;\n    return `<button class=\"spec-pick${state.specialty === s ? ' active' : ''}\" data-spec=\"${s}\">${s}${tag}</button>`;\n  }).join('');\n  $$('[data-spec]').forEach(b => b.addEventListener('click', () => {\n    state.specialty = b.dataset.spec;\n    renderSpecialties();\n    compute();\n  }));\n}\n\nfunction calc() {\n  const base = PILLAR_BASE[state.pillar];\n  const specMult = SPECIALTY_MULT[state.specialty] || 1.0;\n  const hourly = base.hourly * specMult;\n\n  const baseFee = hourly * state.duration * state.exp * state.market;\n  const locMult = 1 + (state.locations - 1) * 0.18;\n  const crewMult = 1 + (state.crew - 1) * 0.35;\n  const deliverables = base.unit * state.deliver * state.exp * state.market;\n  const usage = state.usage;\n  const revs = Math.max(0, state.revisions - 2) * 140;\n  let addons = revs;\n  if (state.travel) addons += 550;\n  if (state.raw) addons += (baseFee + deliverables) * 0.10;\n  if (state.rush) addons += (baseFee + deliverables) * 0.15;\n\n  const subtotal = (baseFee * locMult * crewMult + deliverables) * usage + addons;\n  const costs = state.costs.reduce((a, b) => a + Number(b || 0), 0);\n  const quote = subtotal + costs;\n  const net = quote - costs;\n  const margin = quote > 0 ? Math.round((net / quote) * 100) : 0;\n\n  return {\n    hourly,\n    base: Math.round(baseFee * locMult * crewMult),\n    deliverables: Math.round(deliverables),\n    usage, addons: Math.round(addons),\n    costs, quote: Math.round(quote), net: Math.round(net), margin\n  };\n}\n\nfunction suggestedPackages(q) {\n  return [\n    { name: \"Essential\", pct: 0.7, blurb: \"Streamlined single-deliverable scope.\" },\n    { name: \"Signature\", pct: 1.0, blurb: \"Your default working scope. List this front-and-center.\" },\n    { name: \"Editorial\", pct: 2.2, blurb: \"Crewed, multi-location, premium usage rights.\" }\n  ].map(p => ({ ...p, price: Math.round(q * p.pct / 50) * 50 }));\n}\n\nfunction compute() {\n  const r = calc();\n  $('#quote-out').textContent = fmt(r.quote);\n  $('#base-out').textContent = fmt(r.base);\n  $('#del-out').textContent = fmt(r.deliverables);\n  $('#usage-out').textContent = '×' + state.usage.toFixed(2);\n  $('#addon-out').textContent = fmt(r.addons);\n  $('#cost-out').textContent = fmt(r.costs);\n  $('#net-out').textContent = fmt(r.net);\n  $('#margin-out').textContent = r.margin + '%';\n  $('#cost-total').textContent = fmt(r.costs);\n  $('#adj-base').textContent = fmt(r.hourly) + '/hr';\n\n  $('#retainer-out').textContent = fmt(r.quote / 2);\n  $('#release-out').textContent = fmt(r.quote / 2);\n\n  const pillar = window.CB.pillarByKey(state.pillar);\n  const expLabel = state.exp === 0.7 ? '2–3 yrs' : state.exp === 1.4 ? '7+ yrs' : '4–6 yrs';\n  const mktLabel = state.market === 1.4 ? 'NYC/LA/SF' : state.market === 1.25 ? 'Major US metro' :\n                   state.market === 1.1 ? 'Mid-tier US' : state.market === 0.92 ? 'Smaller US metro' : 'Other US';\n  const durLabel = state.duration === 4 ? 'Half-day' : state.duration === 8 ? 'Full-day' : state.duration === 16 ? '2-day' : '3-day';\n  $('#quote-sub').textContent = `${durLabel} · ${pillar.label} · ${state.specialty} · ${mktLabel} · ${expLabel}`;\n\n  // packages\n  const pkgs = suggestedPackages(r.quote);\n  $('#pkg-grid').innerHTML = pkgs.map((p, i) => `\n    <div class=\"pkg-card${i === 1 ? ' recommended' : ''}\">\n      <div class=\"flex items-center justify-between mb-2\">\n        <div class=\"text-sm font-medium serif\">${p.name}</div>\n        ${i === 1 ? '<span class=\"tag-gold\">Recommended</span>' : ''}\n      </div>\n      <div class=\"flex items-baseline gap-1 mb-2\">\n        <span class=\"text-2xl serif gold-text\">${fmt(p.price)}</span>\n        <span class=\"text-[10px] text-[var(--text-dim)]\">USD</span>\n      </div>\n      <div class=\"text-[11px] text-[var(--text-secondary)] leading-relaxed\">${p.blurb}</div>\n    </div>\n  `).join('');\n\n  // slider fill visuals\n  ['loc-slider','deliver-slider','crew-slider','rev-slider'].forEach(id => {\n    const el = document.getElementById(id);\n    if (!el) return;\n    const p = ((el.value - el.min) / (el.max - el.min)) * 100;\n    el.style.setProperty('--p', p + '%');\n  });\n}\n\n// ===== BIND =====\nrenderPillars();\nrenderSpecialties();\n\n$('#market').addEventListener('change', e => { state.market = parseFloat(e.target.value); compute(); });\n$$('[data-exp]').forEach(b => b.addEventListener('click', () => {\n  $$('[data-exp]').forEach(x => x.classList.remove('active'));\n  b.classList.add('active');\n  state.exp = parseFloat(b.dataset.exp);\n  compute();\n}));\n$$('[data-dur]').forEach(b => b.addEventListener('click', () => {\n  $$('[data-dur]').forEach(x => x.classList.remove('active'));\n  b.classList.add('active');\n  state.duration = parseInt(b.dataset.dur);\n  const out = state.duration === 4 ? 'Half-day · 4 hr' : state.duration === 8 ? 'Full-day · 8 hr' : state.duration === 16 ? '2-day · 16 hr' : '3-day · 24 hr';\n  $('#duration-out').textContent = out;\n  compute();\n}));\n$('#loc-slider').addEventListener('input', e => { state.locations = parseInt(e.target.value); $('#loc-out').textContent = state.locations + ' location' + (state.locations > 1 ? 's' : ''); compute(); });\n$('#deliver-slider').addEventListener('input', e => { state.deliver = parseInt(e.target.value); $('#deliver-out').textContent = state.deliver; compute(); });\n$('#crew-slider').addEventListener('input', e => {\n  state.crew = parseInt(e.target.value);\n  $('#crew-out').textContent = state.crew === 1 ? '1 (just you)' : state.crew + '-person crew';\n  compute();\n});\n$('#rev-slider').addEventListener('input', e => {\n  state.revisions = parseInt(e.target.value);\n  const extra = state.revisions > 2 ? ' (+$' + (state.revisions - 2) * 140 + ')' : ' included';\n  $('#rev-out').textContent = state.revisions + extra;\n  compute();\n});\n$('#usage').addEventListener('change', e => { state.usage = parseFloat(e.target.value); compute(); });\n$('#travel').addEventListener('change', e => { state.travel = e.target.checked; compute(); });\n$('#raw').addEventListener('change', e => { state.raw = e.target.checked; compute(); });\n$('#rush').addEventListener('change', e => { state.rush = e.target.checked; compute(); });\n\n$$('[data-cost]').forEach((el, i) => el.addEventListener('input', e => {\n  state.costs[i] = e.target.value;\n  compute();\n}));\n\ncompute();\n"
  },
  "creatorNetwork": {
    "html": "<main style=\"position:relative;z-index:10; padding-top:5.5rem;\">\n\n<!-- ===== HEADER ===== -->\n<section class=\"px-6 lg:px-16 pt-10 pb-6\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"flex items-center gap-2 text-[11px] text-[var(--text-dim)] mb-4 reveal-up\">\n      <a href=\"/\" class=\"hover:text-[var(--text)] transition-colors\">Home</a>\n      <span class=\"opacity-40\">/</span>\n      <span class=\"text-[var(--text)]\">Creator Network</span>\n    </div>\n    <div class=\"grid lg:grid-cols-12 gap-6 items-end reveal-up\">\n      <div class=\"lg:col-span-7\">\n        <div class=\"eyebrow mb-2\">State creator networks</div>\n        <h1 class=\"text-4xl md:text-5xl serif font-medium leading-[1.05]\">\n          A trusted local circuit. <span class=\"gold-text\">Verified only.</span>\n        </h1>\n        <p class=\"text-sm text-[var(--text-secondary)] max-w-lg mt-4\">\n          Referrals, gear swaps, collab requests, and gig leads — organized by state so the conversation stays local. No DM scraping, no contact poaching, no general-marketplace noise.\n        </p>\n      </div>\n      <div class=\"lg:col-span-5 grid grid-cols-3 gap-3\">\n        <div class=\"liquid-glass rounded-xl p-3 text-center\">\n          <div class=\"text-2xl serif gold-text leading-none\" id=\"stat-creators\">—</div>\n          <div class=\"text-[9px] uppercase tracking-wider text-[var(--text-dim)] mt-1\">Creators</div>\n        </div>\n        <div class=\"liquid-glass rounded-xl p-3 text-center\">\n          <div class=\"text-2xl serif gold-text leading-none\" id=\"stat-posts\">—</div>\n          <div class=\"text-[9px] uppercase tracking-wider text-[var(--text-dim)] mt-1\">Posts today</div>\n        </div>\n        <div class=\"liquid-glass rounded-xl p-3 text-center\">\n          <div class=\"text-2xl serif gold-text leading-none\" id=\"stat-active\">—</div>\n          <div class=\"text-[9px] uppercase tracking-wider text-[var(--text-dim)] mt-1\">Active now</div>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ===== STATE PICKER ===== -->\n<section class=\"px-6 lg:px-16 py-6\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <div class=\"flex items-center justify-between mb-3\">\n      <div class=\"text-[10px] tracking-[0.2em] uppercase text-[var(--text-dim)]\">Choose your state</div>\n      <div class=\"flex items-center gap-2 text-[11px] text-[var(--text-dim)]\">\n        <span class=\"online-dot\"></span> Active networks pulse green\n      </div>\n    </div>\n    <div class=\"grid grid-cols-3 sm:grid-cols-5 md:grid-cols-6 lg:grid-cols-12 gap-2\" id=\"state-grid\"></div>\n  </div>\n</section>\n\n<!-- ===== FEED + CHAT ===== -->\n<section class=\"px-6 lg:px-16 pb-24 pt-4\">\n  <div class=\"max-w-[1400px] mx-auto\">\n    <!-- ACTIVE STATE BANNER -->\n    <div class=\"liquid-glass rounded-2xl p-6 mb-6 reveal-up flex flex-col md:flex-row md:items-center md:justify-between gap-4\">\n      <div>\n        <div class=\"flex items-baseline gap-3 mb-1\">\n          <span class=\"serif text-3xl gold-text\" id=\"active-abbr\">CA</span>\n          <span class=\"serif text-2xl\" id=\"active-name\">California Network</span>\n          <span class=\"tag-green\">Verified creators only</span>\n        </div>\n        <p class=\"text-xs text-[var(--text-secondary)]\" id=\"active-blurb\">142 verified creators · LA, SF, San Diego, Sacramento, OC, San Jose.</p>\n      </div>\n      <div class=\"flex gap-2\">\n        <button class=\"btn-ghost text-xs\">\n          <svg class=\"w-3.5 h-3.5\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 5h14M5 12h14M5 19h14\"/></svg>\n          Compose post\n        </button>\n        <button class=\"btn-gold text-xs\">\n          <svg class=\"w-3.5 h-3.5\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z\"/></svg>\n          Join chat\n        </button>\n      </div>\n    </div>\n\n    <div class=\"grid lg:grid-cols-12 gap-6\">\n      <!-- FEED -->\n      <div class=\"lg:col-span-8\">\n        <div class=\"flex items-center gap-2 mb-4 flex-wrap\">\n          <button class=\"filter-pill active\" data-type=\"all\" style=\"display:inline-flex;align-items:center;gap:0.4rem;padding:0.4rem 0.8rem;border-radius:8px;font-size:11px;color:var(--text-secondary);border:1px solid var(--border);background:rgba(255,255,255,0.02);cursor:pointer;\">All posts</button>\n          <button class=\"filter-pill\" data-type=\"referral\">Referrals</button>\n          <button class=\"filter-pill\" data-type=\"gear\">Gear swap</button>\n          <button class=\"filter-pill\" data-type=\"collab\">Collabs</button>\n          <button class=\"filter-pill\" data-type=\"lead\">Gig leads</button>\n        </div>\n        <div class=\"space-y-3\" id=\"feed\"></div>\n      </div>\n\n      <!-- CHAT -->\n      <div class=\"lg:col-span-4\">\n        <div class=\"liquid-glass rounded-2xl overflow-hidden\" style=\"position:sticky; top:6rem;\">\n          <div class=\"px-5 py-4 border-b border-[var(--border)] flex items-center justify-between\">\n            <div>\n              <div class=\"eyebrow mb-0.5\">Live chat</div>\n              <div class=\"text-sm font-medium\" id=\"chat-state\">California</div>\n            </div>\n            <div class=\"flex items-center gap-1.5 text-[11px] text-[var(--text-secondary)]\">\n              <span class=\"online-dot\"></span> <span id=\"online-count\">23</span> online\n            </div>\n          </div>\n\n          <div class=\"flex gap-1 px-4 py-3 border-b border-[var(--border)] flex-wrap\" id=\"channels\">\n            <button class=\"chat-channel active\" data-ch=\"general\"><span class=\"hash\">#</span>general</button>\n            <button class=\"chat-channel\" data-ch=\"referrals\"><span class=\"hash\">#</span>referrals</button>\n            <button class=\"chat-channel\" data-ch=\"gear\"><span class=\"hash\">#</span>gear-swap</button>\n            <button class=\"chat-channel\" data-ch=\"leads\"><span class=\"hash\">#</span>gig-leads</button>\n          </div>\n\n          <div class=\"px-3 py-3 space-y-1 max-h-[420px] overflow-y-auto\" id=\"chat-stream\"></div>\n\n          <div class=\"border-t border-[var(--border)] p-3 flex items-center gap-2\">\n            <input type=\"text\" id=\"chat-input\" placeholder=\"Message #general…\" class=\"flex-1 bg-transparent border-0 text-sm py-2 px-2 focus:outline-none placeholder:text-[var(--text-dim)]\" style=\"color:var(--text);\">\n            <button id=\"chat-send\" class=\"btn-gold\" style=\"padding:0.5rem 0.8rem;font-size:11px;\">Send</button>\n          </div>\n        </div>\n\n        <!-- NETWORK RULES -->\n        <div class=\"liquid-glass rounded-2xl p-5 mt-5\">\n          <div class=\"eyebrow mb-3\">Network rules</div>\n          <ul class=\"space-y-2.5 text-xs text-[var(--text-secondary)]\">\n            <li class=\"flex gap-2\"><svg class=\"w-3 h-3 text-[var(--gold)] mt-1 shrink-0\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 13l4 4L19 7\"/></svg>Verified accounts only · no off-platform contact sharing.</li>\n            <li class=\"flex gap-2\"><svg class=\"w-3 h-3 text-[var(--gold)] mt-1 shrink-0\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 13l4 4L19 7\"/></svg>Job leads route through the Project Board, not DMs.</li>\n            <li class=\"flex gap-2\"><svg class=\"w-3 h-3 text-[var(--gold)] mt-1 shrink-0\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 13l4 4L19 7\"/></svg>Referrals earn 3% of completed project value.</li>\n            <li class=\"flex gap-2\"><svg class=\"w-3 h-3 text-[var(--gold)] mt-1 shrink-0\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 13l4 4L19 7\"/></svg>Be local. State conversations stay state-specific.</li>\n          </ul>\n        </div>\n      </div>\n    </div>\n  </div>\n</section>\n\n</main>",
    "script": "\n\n\n// ===== STATES =====\nconst STATES = [\n  { abbr: \"CA\", name: \"California\",   creators: 142, posts: 18, active: 23, hot: true },\n  { abbr: \"NY\", name: \"New York\",     creators: 118, posts: 14, active: 19, hot: true },\n  { abbr: \"TX\", name: \"Texas\",        creators: 89,  posts: 11, active: 12, hot: true },\n  { abbr: \"FL\", name: \"Florida\",      creators: 76,  posts: 9,  active: 14, hot: true },\n  { abbr: \"IL\", name: \"Illinois\",     creators: 54,  posts: 5,  active: 7,  hot: false },\n  { abbr: \"GA\", name: \"Georgia\",      creators: 47,  posts: 6,  active: 8,  hot: true },\n  { abbr: \"AZ\", name: \"Arizona\",      creators: 38,  posts: 7,  active: 9,  hot: true },\n  { abbr: \"WA\", name: \"Washington\",   creators: 41,  posts: 4,  active: 6,  hot: false },\n  { abbr: \"MA\", name: \"Massachusetts\",creators: 32,  posts: 3,  active: 4,  hot: false },\n  { abbr: \"CO\", name: \"Colorado\",     creators: 28,  posts: 4,  active: 5,  hot: false },\n  { abbr: \"PA\", name: \"Pennsylvania\", creators: 31,  posts: 2,  active: 3,  hot: false },\n  { abbr: \"NC\", name: \"N. Carolina\",  creators: 26,  posts: 3,  active: 4,  hot: false },\n  { abbr: \"OR\", name: \"Oregon\",       creators: 22,  posts: 2,  active: 3,  hot: false },\n  { abbr: \"MI\", name: \"Michigan\",     creators: 20,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"OH\", name: \"Ohio\",         creators: 19,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"MN\", name: \"Minnesota\",    creators: 17,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"NV\", name: \"Nevada\",       creators: 21,  posts: 2,  active: 3,  hot: false },\n  { abbr: \"UT\", name: \"Utah\",         creators: 15,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"TN\", name: \"Tennessee\",    creators: 23,  posts: 3,  active: 4,  hot: false },\n  { abbr: \"VA\", name: \"Virginia\",     creators: 18,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"OK\", name: \"Oklahoma\",     creators: 9,   posts: 0,  active: 1,  hot: false },\n  { abbr: \"WI\", name: \"Wisconsin\",    creators: 11,  posts: 1,  active: 1,  hot: false },\n  { abbr: \"MO\", name: \"Missouri\",     creators: 13,  posts: 1,  active: 2,  hot: false },\n  { abbr: \"LA\", name: \"Louisiana\",    creators: 16,  posts: 2,  active: 3,  hot: false }\n];\n\nconst FEEDS = {\n  CA: [\n    { type: \"lead\", icon: \"·\", author: \"Naomi Greene\", studio: \"Greene Street Films · LA\", pillar: \"Video Production\", specialty: \"Brand Films & Commercials\", avatar: \"/images/creatorbridge/handoff/photo-1531746020798-e6953c6e8e04.png\", time: \"1 hr ago\", body: \"Brand wants a 2-day shoot in Malibu next month, full-day rate $4-5k range. Open to one referral — DM if you have hospitality-brand experience and a clean reel.\", replies: 4 },\n    { type: \"gear\", icon: \"·\", author: \"David Park\", studio: \"LensCraft · Burbank\", pillar: \"Video Production\", specialty: \"Brand Films & Commercials\", avatar: \"/images/creatorbridge/handoff/photo-1438761681033-6461ffad8d80.png\", time: \"3 hr ago\", body: \"Selling: Sony FX6 body, 600 hours, no shutter issues, includes V-mount plate and two batteries. $5,800 firm. CA pickup only.\", replies: 9 },\n    { type: \"collab\", icon: \"·\", author: \"Lia Romero\", studio: \"Indie cinematographer · SF\", pillar: \"Video Production\", specialty: \"Music Videos\", avatar: \"/images/creatorbridge/handoff/photo-1502823403499-6ccfcf4fb453.png\", time: \"5 hr ago\", body: \"Doing a passion short over July — looking for a colorist who'll work for backend. Festival-track piece, fully insured.\", replies: 2 },\n    { type: \"referral\", icon: \"·\", author: \"Ava Tanaka\", studio: \"Tanaka Visuals · LA\", pillar: \"Photography\", specialty: \"Editorial & Press\", avatar: \"/images/creatorbridge/handoff/photo-1544005313-94ddf0286df2.png\", time: \"Yesterday\", body: \"Just wrapped a 3-month brand campaign with Northgrade Color for finishing — Aaron is incredibly fast and his eye for editorial grades is unmatched. Highly recommend for anyone in the lane.\", replies: 7 }\n  ],\n  NY: [\n    { type: \"lead\", icon: \"·\", author: \"Jordan Mitchell\", studio: \"SoundWave · NYC\", pillar: \"Post Production\", specialty: \"Podcast Audio Editing\", avatar: \"/images/creatorbridge/handoff/photo-1507003211169-0a1dd7228f2d.png\", time: \"32 min ago\", body: \"Studio has 2 open recording days next week. Manhattan podcast/voiceover gigs — referral fee on the table for anyone who fills them.\", replies: 3 },\n    { type: \"gear\", icon: \"·\", author: \"Sofia Pellizzari\", studio: \"Pellizzari Editorial · NYC\", pillar: \"Photography\", specialty: \"Editorial & Press\", avatar: \"/images/creatorbridge/handoff/photo-1487412720507-e7ab37603c6f.png\", time: \"2 hr ago\", body: \"Renting out: Profoto B10 Plus duo pack with stands, $80/day. Manhattan delivery if needed.\", replies: 1 },\n    { type: \"collab\", icon: \"·\", author: \"Marcus Bell\", studio: \"Bell Editorial · Brooklyn\", pillar: \"Post Production\", specialty: \"Color Grading\", avatar: \"/images/creatorbridge/handoff/photo-1463453091185-61582044d556.png\", time: \"4 hr ago\", body: \"Looking for a stylist for a 4-page editorial test shoot. Test rate, full credits, published portfolio piece in return.\", replies: 6 },\n    { type: \"referral\", icon: \"·\", author: \"Naomi Greene\", studio: \"Greene Street Films\", pillar: \"Video Production\", specialty: \"Brand Films & Commercials\", avatar: \"/images/creatorbridge/handoff/photo-1531746020798-e6953c6e8e04.png\", time: \"1 day ago\", body: \"Bondi Studio crushed a quick Reels package for a launch I produced — turnaround was 4 days. Worth knowing they exist.\", replies: 4 }\n  ],\n  TX: [\n    { type: \"collab\", icon: \"·\", author: \"Mateo Reyes\", studio: \"Skyframe Aerial · Austin\", pillar: \"Video Production\", specialty: \"Drone & Aerial Video\", avatar: \"/images/creatorbridge/handoff/photo-1500648767791-00dcc994a43e.png\", time: \"2 hr ago\", body: \"Heading out to West Texas for a 3-day aerial shoot June 18-20. Have an open seat in the truck if anyone wants to share fuel + b-roll a side project.\", replies: 3 },\n    { type: \"gear\", icon: \"·\", author: \"Kelsey Trent\", studio: \"Trent Productions · Houston\", pillar: \"Video Production\", specialty: \"Corporate & Internal Video\", avatar: \"/images/creatorbridge/handoff/photo-1573497019940-1c28c88b4f3e.png\", time: \"Yesterday\", body: \"Selling a barely-used Aputure 600D Pro with softbox + grid. $1,400. Houston only.\", replies: 5 }\n  ],\n  FL: [\n    { type: \"lead\", icon: \"·\", author: \"Aria Vasquez\", studio: \"Aria Visual Studio · Miami\", pillar: \"Photography\", specialty: \"Brand & Commercial Photography\", avatar: \"/images/creatorbridge/handoff/photo-1494790108377-be9c29b29330.png\", time: \"1 hr ago\", body: \"Hotel campaign overbooked next month — could route a similar gig to a Florida shooter with editorial experience. Verified-only DMs.\", replies: 5 },\n    { type: \"referral\", icon: \"·\", author: \"Carlos Mendez\", studio: \"Coast Studios · Tampa\", pillar: \"Photography\", specialty: \"Food & Hospitality\", avatar: \"/images/creatorbridge/handoff/photo-1607746882042-944635dfe10e.png\", time: \"3 hr ago\", body: \"Worked with Aria on a Soho House Miami shoot last quarter — full pre-pro deck, tight call sheet, deliverables on time. Set the bar for the rest of the year.\", replies: 2 }\n  ],\n  GA: [\n    { type: \"lead\", icon: \"·\", author: \"Dre Williams\", studio: \"Cumulus Events · Atlanta\", pillar: \"Video Production\", specialty: \"Event & Conference Video\", avatar: \"/images/creatorbridge/handoff/photo-1607746882042-944635dfe10e.png\", time: \"2 hr ago\", body: \"Tech conference in Midtown needs a second-shooter June 14-15. Multi-cam experience preferred. Going through CB project board.\", replies: 4 }\n  ]\n};\n\nconst CHAT = {\n  general: [\n    { name: \"Naomi G.\", time: \"10:32\", avatar: \"/images/creatorbridge/handoff/photo-1531746020798-e6953c6e8e04.png\", text: \"Good morning ☕️ shooting a brand piece in Venice today, weather's perfect\" },\n    { name: \"Aria V.\", time: \"10:35\", avatar: \"/images/creatorbridge/handoff/photo-1494790108377-be9c29b29330.png\", text: \"Jealous. Miami's humid AF. Crew suiting up for an indoor shoot all day\" },\n    { name: \"David P.\", time: \"10:38\", avatar: \"/images/creatorbridge/handoff/photo-1438761681033-6461ffad8d80.png\", text: \"Anyone tried the new Sony Burano on a real job? Considering renting for next week\" },\n    { name: \"Mateo R.\", time: \"10:41\", avatar: \"/images/creatorbridge/handoff/photo-1500648767791-00dcc994a43e.png\", text: \"Cleared for Part 107 recertification today — back in the air next week\" },\n    { name: \"Jordan M.\", time: \"10:44\", avatar: \"/images/creatorbridge/handoff/photo-1507003211169-0a1dd7228f2d.png\", text: \"Booked 4 podcast clients off the project board in May. CB scoring better than any cold outbound I've ever done\" },\n    { name: \"Sofia P.\", time: \"10:48\", avatar: \"/images/creatorbridge/handoff/photo-1487412720507-e7ab37603c6f.png\", text: \"Lighting test shots from yesterday — full client approval before we even broke for lunch\" }\n  ],\n  referrals: [\n    { name: \"Aria V.\", time: \"9:14\", avatar: \"/images/creatorbridge/handoff/photo-1494790108377-be9c29b29330.png\", text: \"Boutique hotel rebrand looking for video — anyone California-based with hospitality reel?\" },\n    { name: \"Naomi G.\", time: \"9:18\", avatar: \"/images/creatorbridge/handoff/photo-1531746020798-e6953c6e8e04.png\", text: \"I'll bite — DMing now\" },\n    { name: \"David P.\", time: \"9:22\", avatar: \"/images/creatorbridge/handoff/photo-1438761681033-6461ffad8d80.png\", text: \"Aria solid pick, his Standard Hotels work was 10/10\" }\n  ],\n  gear: [\n    { name: \"David P.\", time: \"8:52\", avatar: \"/images/creatorbridge/handoff/photo-1438761681033-6461ffad8d80.png\", text: \"Selling FX6, see today's main feed for details\" },\n    { name: \"Sofia P.\", time: \"9:01\", avatar: \"/images/creatorbridge/handoff/photo-1487412720507-e7ab37603c6f.png\", text: \"Renting Profoto B10 Plus duo · $80/day · Manhattan\" },\n    { name: \"Mateo R.\", time: \"9:11\", avatar: \"/images/creatorbridge/handoff/photo-1500648767791-00dcc994a43e.png\", text: \"Anyone got an extra ND filter set in 4×5.65? Mine fell into Lake Travis on Saturday 🪦\" }\n  ],\n  leads: [\n    { name: \"Aria V.\", time: \"11:02\", avatar: \"/images/creatorbridge/handoff/photo-1494790108377-be9c29b29330.png\", text: \"Routing 2 commercial photo briefs to FL/CA — see today's main feed\" },\n    { name: \"Dre W.\", time: \"11:08\", avatar: \"/images/creatorbridge/handoff/photo-1607746882042-944635dfe10e.png\", text: \"Atlanta tech conf needs 2nd shooter, June 14-15. Posted to project board, applying via CB\" }\n  ]\n};\n\nconst state = { active: 'CA', type: 'all', channel: 'general' };\nconst $ = (s) => root.querySelector(s);\nconst $$ = (s) => Array.from(root.querySelectorAll(s));\n\nfunction renderStates() {\n  $('#state-grid').innerHTML = STATES.map(s => `\n    <button class=\"state-tile${s.hot ? ' hot' : ''}${state.active === s.abbr ? ' active' : ''}\" data-st=\"${s.abbr}\">\n      <div class=\"abbr\">${s.abbr}</div>\n      <div class=\"name\">${s.name}</div>\n      <div class=\"count\">${s.creators} verified</div>\n    </button>`).join('');\n  $$('[data-st]').forEach(b => b.addEventListener('click', () => {\n    state.active = b.dataset.st;\n    renderAll();\n  }));\n}\n\nfunction renderFeed() {\n  const list = (FEEDS[state.active] || []).filter(p => state.type === 'all' || p.type === state.type);\n  const feed = $('#feed');\n  if (!list.length) {\n    feed.innerHTML = `\n      <div class=\"liquid-glass rounded-2xl p-8 text-center\">\n        <div class=\"serif text-xl mb-2\">Quiet here.</div>\n        <div class=\"text-xs text-[var(--text-dim)]\">No posts in this lane today. Switch tabs or compose the first one.</div>\n      </div>`;\n    return;\n  }\n  feed.innerHTML = list.map(p => `\n    <div class=\"post-card\">\n      <div class=\"post-meta\">\n        <div class=\"post-avatar\"><img src=\"${p.avatar}\" alt=\"\"></div>\n        <div class=\"flex-1\">\n          <div class=\"flex items-center gap-2 flex-wrap\">\n            <div class=\"text-sm font-medium\">${p.author}</div>\n            <span class=\"tag-gold\">${typeLabel(p.type)}</span>\n          </div>\n          <div class=\"text-[11px] text-[var(--text-dim)]\">${p.studio} · ${p.time}</div>\n          ${p.pillar ? `<div class=\"creator-pillar-mini\"><span class=\"pdot\"></span><span class=\"plabel\">${p.pillar}</span><span class=\"psep\">·</span><span class=\"pspec\">${p.specialty}</span></div>` : ''}\n        </div>\n        <button class=\"text-[var(--text-dim)] hover:text-[var(--gold)] transition-colors\" style=\"background:none;border:none;cursor:pointer;\">\n          <svg width=\"16\" height=\"16\" fill=\"currentColor\" viewBox=\"0 0 24 24\"><circle cx=\"5\" cy=\"12\" r=\"1.5\"/><circle cx=\"12\" cy=\"12\" r=\"1.5\"/><circle cx=\"19\" cy=\"12\" r=\"1.5\"/></svg>\n        </button>\n      </div>\n      <p class=\"text-sm text-[var(--text)]/90 leading-relaxed mb-4\">${p.body}</p>\n      <div class=\"flex items-center gap-4 text-[11px] text-[var(--text-dim)] pt-3 border-t border-[var(--border)]\">\n        <button class=\"flex items-center gap-1.5 hover:text-[var(--gold)] transition-colors\" style=\"background:none;border:none;cursor:pointer;color:inherit;\">\n          <svg width=\"14\" height=\"14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z\"/></svg>\n          ${p.replies} replies\n        </button>\n        <button class=\"flex items-center gap-1.5 hover:text-[var(--gold)] transition-colors\" style=\"background:none;border:none;cursor:pointer;color:inherit;\">\n          <svg width=\"14\" height=\"14\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.6\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z\"/></svg>\n          Save\n        </button>\n        <button class=\"flex items-center gap-1.5 hover:text-[var(--gold)] transition-colors ml-auto\" style=\"background:none;border:none;cursor:pointer;color:inherit;\">\n          Reply\n          <svg width=\"12\" height=\"12\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" viewBox=\"0 0 24 24\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M14 5l7 7m0 0l-7 7m7-7H3\"/></svg>\n        </button>\n      </div>\n    </div>`).join('');\n}\n\nfunction typeLabel(t) {\n  return { lead: 'Gig lead', gear: 'Gear', collab: 'Collab', referral: 'Referral' }[t] || t;\n}\n\nfunction renderChat() {\n  const msgs = CHAT[state.channel] || [];\n  $('#chat-stream').innerHTML = msgs.map(m => `\n    <div class=\"chat-msg\">\n      <div class=\"av\"><img src=\"${m.avatar}\" alt=\"\"></div>\n      <div class=\"flex-1 min-w-0\">\n        <div class=\"flex items-baseline gap-2\">\n          <span class=\"text-xs font-medium\">${m.name}</span>\n          <span class=\"text-[10px] text-[var(--text-dim)]\">${m.time}</span>\n        </div>\n        <div class=\"text-[12px] text-[var(--text)]/90 leading-relaxed\">${m.text}</div>\n      </div>\n    </div>`).join('');\n  // scroll to bottom\n  const stream = $('#chat-stream');\n  stream.scrollTop = stream.scrollHeight;\n  $('#chat-input').placeholder = `Message #${state.channel}…`;\n}\n\nfunction renderHeader() {\n  const s = STATES.find(x => x.abbr === state.active);\n  if (!s) return;\n  $('#active-abbr').textContent = s.abbr;\n  $('#active-name').textContent = s.name + ' Network';\n  $('#active-blurb').textContent = `${s.creators} verified creators · join the local conversation.`;\n  $('#chat-state').textContent = s.name;\n  $('#online-count').textContent = s.active;\n  $('#stat-creators').textContent = s.creators;\n  $('#stat-posts').textContent = s.posts;\n  $('#stat-active').textContent = s.active;\n}\n\nfunction renderAll() {\n  renderStates();\n  renderHeader();\n  renderFeed();\n  renderChat();\n}\n\n// type filter\n$$('[data-type]').forEach(b => b.addEventListener('click', () => {\n  $$('[data-type]').forEach(x => x.classList.remove('active'));\n  b.classList.add('active');\n  state.type = b.dataset.type;\n  renderFeed();\n}));\n\n// channel pick\n$$('[data-ch]').forEach(b => b.addEventListener('click', () => {\n  $$('[data-ch]').forEach(x => x.classList.remove('active'));\n  b.classList.add('active');\n  state.channel = b.dataset.ch;\n  renderChat();\n}));\n\n// send (mock)\nfunction send() {\n  const input = $('#chat-input');\n  const text = input.value.trim();\n  if (!text) return;\n  CHAT[state.channel].push({\n    name: 'You', time: 'now',\n    avatar: '/images/creatorbridge/handoff/photo-1599566150163-29194dcaad36.png',\n    text\n  });\n  input.value = '';\n  renderChat();\n}\n$('#chat-send').addEventListener('click', send);\n$('#chat-input').addEventListener('keydown', e => { if (e.key === 'Enter') send(); });\n\nrenderAll();\n"
  }
};
